package com.infy.inventrack.catalog.controller; import com.infy.inventrack.catalog.service.ProductService; import com.infy.inventrack.common.dto.*; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.math.BigDecimal; import java.util.List; @RestController @RequestMapping("/products") public class ProductController { private final ProductService service; public ProductController(ProductService s){service=s;} @PostMapping public ResponseEntity<String> create(@Valid @RequestBody ProductRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.createProduct(r));} @GetMapping("/{sku}") public ResponseEntity<ProductResponse> get(@PathVariable String sku){return ResponseEntity.ok(service.getProductBySku(sku));} @PutMapping("/{sku}") public ResponseEntity<String> update(@PathVariable String sku,@Valid @RequestBody ProductRequest r){return ResponseEntity.ok(service.updateProduct(sku,r));} @DeleteMapping("/{sku}") public ResponseEntity<String> delete(@PathVariable String sku){return ResponseEntity.ok(service.deleteProduct(sku));} @GetMapping("/search") public ResponseEntity<List<ProductResponse>> search(@RequestParam(required=false) String name,@RequestParam(required=false) String category,@RequestParam(required=false) BigDecimal minPrice,@RequestParam(required=false) BigDecimal maxPrice,@RequestParam(defaultValue="0") int page,@RequestParam(defaultValue="5") int size,@RequestParam(defaultValue="category") String sortBy){return ResponseEntity.ok(service.searchProducts(name,category,minPrice,maxPrice,page,size,sortBy));} @GetMapping("/top-expensive") public ResponseEntity<List<ProductResponse>> top(@RequestParam Integer n){return ResponseEntity.ok(service.findTopNExpensiveProducts(n));} @PatchMapping("/{sku}/description") public ResponseEntity<ProductResponse> desc(@PathVariable String sku,@Valid @RequestBody DescriptionUpdateRequest r){return ResponseEntity.ok(service.updateDescription(sku,r));} }
